        byte[] serializedData = serializeObject(testString);

        Object result = null;
        try {
            result = hessianService.deserializeUserData(serializedData);
        } catch (Exception e) {
            fail("反序列化失败：" + e.getMessage());
        }

        assertNotNull("反序列化结果不应为空", result);
        assertEquals("字符串应该正确反序列化", testString, result);
    }

    /**
